def fetch_data_from_accounting_system(start_date, end_date):
    # Fetch data from accounting system (e.g., QuickBooks or Sage)
    # and return as a pandas DataFrame
    data = pd.read_csv('accounting_data.csv')
    data['date'] = pd.to_datetime(data['date'])
    data = data[(data['date'] >= start_date) & (data['date'] <= end_date)]
    return data

def generate_monthly_report(data):
    # Group data by month and generate monthly report
    monthly_report = data.groupby(pd.Grouper(key='date', freq='M')).agg({
        'amount': ['sum', 'mean', 'std'],
        'category': 'count'
    })
    monthly_report.columns = ['total_amount', 'average_amount', 'std_amount', 'num_transactions']
    monthly_report = monthly_report.reset_index()
    return monthly_report

def generate_quarterly_report(data):
    # Group data by quarter and generate quarterly report
    quarterly_report = data.groupby(pd.Grouper(key='date', freq='Q')).agg({
        'amount': ['sum', 'mean', 'std'],
        'category': 'count'
    })
    quarterly_report.columns = ['total_amount', 'average_amount', 'std_amount', 'num_transactions']
    quarterly_report = quarterly_report.reset_index()
    return quarterly_report

def generate_annual_report(data):
    # Group data by year and generate annual report
